-- ============================================================
-- Local-dev seed. Runs automatically after migrations on
-- `supabase db reset`. NEVER applied to prod (Supabase ignores
-- supabase/seed.sql for remote pushes).
--
-- Login: admin@local.test / password
--
-- Stores / vendors / inventory_items below are PULLED FROM PROD
-- via read-only SELECT queries against the linked Supabase project,
-- formatted via Postgres `format('%L', ...)`. Vendor PII fields
-- (contact_name, phone, email) are masked with non-real
-- placeholders before being written to this file. Audit-log entries
-- at the bottom are still synthetic — they reference text item names
-- (no FK to inventory_items), so they keep working.
-- ============================================================

-- ─── admin user ──────────────────────────────────────────
-- gotrue's Go scanner cannot read NULL for the *_token columns even
-- though the columns are nullable. Setting them to '' (empty string)
-- avoids "Database error querying schema" on /token requests.
do $$
declare
  admin_id constant uuid := '11111111-1111-1111-1111-111111111111';
begin
    id, instance_id, aud, role,
    email, encrypted_password,
    email_confirmed_at, created_at, updated_at,
    raw_app_meta_data, raw_user_meta_data,
    is_super_admin, is_anonymous,
    confirmation_token, recovery_token,
    email_change_token_new, email_change,
    email_change_token_current, phone_change,
    phone_change_token, reauthentication_token
  ) values (
    admin_id,
    '00000000-0000-0000-0000-000000000000',
    'authenticated', 'authenticated',
    'admin@local.test',
    crypt('password', gen_salt('bf')),
    now(), now(), now(),
    jsonb_build_object(
      'provider', 'email',
      'providers', array['email'],
      'role', 'admin'
    ),
    '{}'::jsonb,
    false, false,
    '', '', '', '', '', '', '', ''
  )
  on conflict (id) do nothing;

    id, user_id, provider_id, identity_data, provider,
    last_sign_in_at, created_at, updated_at
  ) values (
    gen_random_uuid(), admin_id, admin_id::text,
    jsonb_build_object('sub', admin_id::text, 'email', 'admin@local.test', 'email_verified', true),
    'email', now(), now(), now()
  )
  on conflict (provider_id, provider) do nothing;

  -- brand_id required since spec 012a: admin-role profiles must be
  -- scoped to a brand (CHECK profiles_role_brand_consistent). Local
  -- admin lives in the seed 2AM PROJECT brand.
  values (admin_id, 'Local Admin', 'admin', 'LA', '#378ADD', 'active',
          '2a000000-0000-0000-0000-000000000001')
  on conflict (id) do nothing;
end $$;

-- ─── manager user (regular role, Towson + Frederick only) ─
-- Login: manager@local.test / password
-- Use this account to verify what a non-admin actually sees:
-- store dropdown limited to assigned stores, no admin nav,
-- profiles RLS hides other users' rows.
do $$
declare
  manager_id constant uuid := '22222222-2222-2222-2222-222222222222';
begin
    id, instance_id, aud, role,
    email, encrypted_password,
    email_confirmed_at, created_at, updated_at,
    raw_app_meta_data, raw_user_meta_data,
    is_super_admin, is_anonymous,
    confirmation_token, recovery_token,
    email_change_token_new, email_change,
    email_change_token_current, phone_change,
    phone_change_token, reauthentication_token
  ) values (
    manager_id,
    '00000000-0000-0000-0000-000000000000',
    'authenticated', 'authenticated',
    'manager@local.test',
    crypt('password', gen_salt('bf')),
    now(), now(), now(),
    jsonb_build_object('provider', 'email', 'providers', array['email'], 'role', 'user'),
    '{}'::jsonb,
    false, false,
    '', '', '', '', '', '', '', ''
  )
  on conflict (id) do nothing;

    id, user_id, provider_id, identity_data, provider,
    last_sign_in_at, created_at, updated_at
  ) values (
    gen_random_uuid(), manager_id, manager_id::text,
    jsonb_build_object('sub', manager_id::text, 'email', 'manager@local.test', 'email_verified', true),
    'email', now(), now(), now()
  )
  on conflict (provider_id, provider) do nothing;

  -- brand_id is unconstrained for 'user' role per spec 012a, but we set
  -- it to the seed brand anyway so cross-brand store assignment via
  -- user_stores doesn't trip the user_stores_brand_match trigger.
  values (manager_id, 'Tara Manager', 'user', 'TM', '#E0853B', 'active',
          '2a000000-0000-0000-0000-000000000001')
  on conflict (id) do nothing;
end $$;

-- ─── master user (master role, all stores) ────────────────
-- Login: master@local.test / password
-- master and admin share the same RLS bypass via
-- `auth.jwt() -> 'app_metadata' ->> 'role' IN ('admin','master')`.
-- Useful for testing any UI that special-cases role='master'.
do $$
declare
  master_id constant uuid := '33333333-3333-3333-3333-333333333333';
begin
    id, instance_id, aud, role,
    email, encrypted_password,
    email_confirmed_at, created_at, updated_at,
    raw_app_meta_data, raw_user_meta_data,
    is_super_admin, is_anonymous,
    confirmation_token, recovery_token,
    email_change_token_new, email_change,
    email_change_token_current, phone_change,
    phone_change_token, reauthentication_token
  ) values (
    master_id,
    '00000000-0000-0000-0000-000000000000',
    'authenticated', 'authenticated',
    'master@local.test',
    crypt('password', gen_salt('bf')),
    now(), now(), now(),
    jsonb_build_object('provider', 'email', 'providers', array['email'], 'role', 'master'),
    '{}'::jsonb,
    false, false,
    '', '', '', '', '', '', '', ''
  )
  on conflict (id) do nothing;

    id, user_id, provider_id, identity_data, provider,
    last_sign_in_at, created_at, updated_at
  ) values (
    gen_random_uuid(), master_id, master_id::text,
    jsonb_build_object('sub', master_id::text, 'email', 'master@local.test', 'email_verified', true),
    'email', now(), now(), now()
  )
  on conflict (provider_id, provider) do nothing;

  -- 'master' is admin-equivalent and must have a brand_id per
  -- profiles_role_brand_consistent (see migration 20260509000000).
  values (master_id, 'Mae Master', 'master', 'MM', '#7A4FCF', 'active',
          '2a000000-0000-0000-0000-000000000001')
  on conflict (id) do nothing;
end $$;

-- ─── stores (4, brand-scoped) ───────────────────────────
-- Brand row is inserted by migration 20260504060452_brand_catalog_p1_additive,
-- so it already exists when this seed runs.
on conflict (id) do update set brand_id = excluded.brand_id, name = excluded.name, address = excluded.address;

-- Drop the synthetic Baltimore store that init_schema seeds.
delete from public.stores where id = '00000000-0000-0000-0000-000000000002';

-- ─── store-access grants ─────────────────────────────────
-- Admin + master: all 4 stores. Manager: Towson + Frederick only.
select u.user_id, s.id
from (values
  ('11111111-1111-1111-1111-111111111111'::uuid),
  ('33333333-3333-3333-3333-333333333333'::uuid)
) as u(user_id), public.stores s
on conflict do nothing;

on conflict do nothing;

-- ─── vendors (11, brand-scoped, PII masked) ────────────
on conflict (id) do nothing;

-- ─── recipe_categories ──────────────────────────────────
-- 9 recipe_categories
on conflict (id) do nothing;

-- ─── ingredient_categories ──────────────────────────────
-- 11 ingredient_categories
on conflict (id) do nothing;

-- ─── brands ─────────────────────────────────────────────
on conflict (id) do nothing;

-- ─── catalog_ingredients (143, brand-shared) ──────────
on conflict (id) do nothing;

-- ─── inventory_items (572, per-store) ─────────────────
on conflict (id) do nothing;

-- ─── ingredient_conversions (4) ───────────────────────
on conflict (id) do nothing;

-- ─── recipes (41, brand-scoped) ────────────────────────
on conflict (id) do nothing;

-- ─── prep_recipes (62 incl. version history) ──────────
on conflict (id) do nothing;

-- ─── recipe_ingredients (152) ─────────────────────────
on conflict (id) do nothing;

-- ─── recipe_prep_items (41) ───────────────────────────
on conflict (id) do nothing;

-- ─── prep_recipe_ingredients (464) ────────────────────
on conflict (id) do nothing;

